<?php
/**
 * The template for displaying the footer
 *
 * Contains the closing of the #content div and all content after.
 *
 * @link https://developer.wordpress.org/themes/basics/template-files/#template-partials
 *
 * @package AquaLuxe
 */

?>

	</div><!-- #content -->

	<?php do_action( 'aqualuxe_before_footer' ); ?>

	<footer id="colophon" class="site-footer bg-gray-900 dark:bg-dark-900 text-white pt-12 pb-6">
		<?php if ( get_theme_mod( 'aqualuxe_enable_footer_widgets', true ) ) : ?>
			<div class="footer-widgets container mx-auto px-4">
				<div class="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-<?php echo esc_attr( get_theme_mod( 'aqualuxe_footer_columns', 4 ) ); ?> gap-8">
					<?php
					// Get the number of footer widget areas
					$footer_widget_areas = get_theme_mod( 'aqualuxe_footer_columns', 4 );

					// Loop through each footer widget area
					for ( $i = 1; $i <= $footer_widget_areas; $i++ ) {
						if ( is_active_sidebar( 'footer-' . $i ) ) {
							echo '<div class="footer-widget footer-widget-' . esc_attr( $i ) . '">';
							dynamic_sidebar( 'footer-' . $i );
							echo '</div>';
						}
					}
					?>
				</div>
			</div>
		<?php endif; ?>

		<?php if ( get_theme_mod( 'aqualuxe_enable_footer_menu', true ) && has_nav_menu( 'footer' ) ) : ?>
			<div class="footer-menu container mx-auto px-4 mt-8 mb-6">
				<div class="border-t border-gray-800 dark:border-dark-700 pt-6">
					<nav class="footer-navigation">
						<?php
						wp_nav_menu(
							array(
								'theme_location' => 'footer',
								'menu_id'        => 'footer-menu',
								'menu_class'     => 'flex flex-wrap justify-center space-x-6 text-sm',
								'container'      => false,
								'depth'          => 1,
								'fallback_cb'    => false,
							)
						);
						?>
					</nav>
				</div>
			</div>
		<?php endif; ?>

		<div class="site-info container mx-auto px-4 mt-8">
			<div class="border-t border-gray-800 dark:border-dark-700 pt-6 flex flex-col md:flex-row justify-between items-center">
				<div class="footer-branding mb-4 md:mb-0">
					<?php if ( get_theme_mod( 'aqualuxe_footer_logo' ) ) : ?>
						<div class="footer-logo">
							<a href="<?php echo esc_url( home_url( '/' ) ); ?>" rel="home">
								<img src="<?php echo esc_url( get_theme_mod( 'aqualuxe_footer_logo' ) ); ?>" alt="<?php bloginfo( 'name' ); ?>" class="h-12 w-auto">
							</a>
						</div>
					<?php else : ?>
						<div class="site-title text-xl font-serif font-bold text-white">
							<a href="<?php echo esc_url( home_url( '/' ) ); ?>" rel="home" class="text-white hover:text-primary-400 transition-colors duration-300">
								<?php bloginfo( 'name' ); ?>
							</a>
						</div>
					<?php endif; ?>
				</div>

				<div class="footer-copyright text-sm text-gray-400 text-center md:text-right">
					<?php
					$copyright_text = get_theme_mod( 'aqualuxe_copyright_text', '&copy; ' . date( 'Y' ) . ' ' . get_bloginfo( 'name' ) . '. All rights reserved.' );
					echo wp_kses_post( $copyright_text );
